INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('OMEGA_1: Le email sequence timing science: J0 intro → J+3 valeur → J+7 social proof → J+12 urgence → J+18 FOMO → J+25 breakup. Espacement croissant.', 'Email sequence: J0→J3→J7→J12→J18→J25. Espacement croissant', 'email', 'best_practice', 0.88, 'omega', 'system'),
('OMEGA_2: Le commercial deal momentum: chaque interaction doit avoir un next step defini. Pas de next step = deal mort en 7 jours.', 'Deal momentum: chaque interaction = next step defini. Sinon mort 7j', 'commercial', 'best_practice', 0.88, 'omega', 'system'),
('OMEGA_3: Le content algorithmic boost: commenter son propre post avec un commentaire de valeur (50+ mots) dans les 5 premieres minutes = +30% portee.', 'Commenter son post 50+ mots 5 min = +30% portee', 'content', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_4: Le SEO programmatic pages: creer des pages automatisees pour chaque combinaison (service + ville, produit + categorie). 1000 pages = 1000 mots-cles longue traine.', 'SEO programmatic: pages auto service+ville = 1000 mots-cles longue traine', 'seo', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_5: Le ad creative production pipeline: briefing lundi → creation mardi-mercredi → review jeudi → lancement vendredi. Cadence hebdomadaire non-stop.', 'Creative pipeline: brief lun → creation mar-mer → review jeu → lancement ven', 'ads', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_6: Le DM micro-commitment ladder: like → commentaire → reaction story → reponse DM → appel → client. Chaque etape prepare la suivante.', 'DM ladder: like → comment → story → DM → appel → client', 'dm_instagram', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_7: Le WhatsApp catalog best practices: photo HD + description 2 lignes + prix visible + CTA (Commander/Reserver). Les produits avec photo convertissent 3x.', 'WhatsApp catalogue: photo HD + desc 2 lignes + prix + CTA = 3x conversion', 'whatsapp', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_8: Le chatbot progressive disclosure: ne poser que 1 question a la fois. Attendre la reponse avant la suivante. Les chatbots qui posent 3 questions d un coup perdent 60% des users.', 'Chatbot: 1 question a la fois. 3 questions d un coup = -60% users', 'chatbot', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_9: Le GMaps proximity advantage: les entreprises dans un rayon de 1km du chercheur ont 5x plus de chances d apparaitre. L adresse exacte est critique.', 'GMaps proximite: 1km du chercheur = 5x chances apparaitre', 'gmaps', 'insight', 0.82, 'omega', 'system'),
('OMEGA_10: Le TikTok storytelling structure: situation relatable (2s) → complication (3s) → tension (5s) → resolution (3s) → call to action (2s). 15s total.', 'TikTok storytelling: situation 2s → complication 3s → tension 5s → resolution 3s → CTA 2s', 'tiktok_comments', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_11: Le CEO sprint planning: chaque 2 semaines, definir les 3 objectifs prioritaires. Chaque objectif = 1-2 key results mesurables. Review le dernier jour.', 'CEO sprint 2 sem: 3 objectifs × 1-2 KR mesurables. Review dernier jour', 'ceo', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_12: Le retention customer effort score (CES): mesurer apres chaque interaction support. CES faible (effort faible) = retention haute. CES eleve = churn risk.', 'CES: effort faible = retention haute. Effort eleve = churn risk', 'retention', 'insight', 0.85, 'omega', 'system'),
('OMEGA_13: Le onboarding wizard anti-pattern: ne jamais demander des informations non-essentielles pendant l onboarding. Chaque champ supplementaire = -10% completion.', 'Onboarding: chaque champ non-essentiel = -10% completion. Minimum de champs', 'onboarding', 'best_practice', 0.88, 'omega', 'system'),
('OMEGA_14: Le comptable financial forecasting: projeter MRR × 12 = ARR previsionnel. Ajouter expansion revenue (historique %). Soustraire churn (historique %). = ARR fin d annee.', 'Forecast: MRR×12 + expansion% - churn% = ARR fin annee', 'comptable', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_15: Le RH remote onboarding: J1 welcome call + setup outils, J2-5 shadowing, S2 premier projet, S3-4 autonomie progressive, M2 evaluation 60 jours.', 'Remote onboarding: J1 welcome, J2-5 shadow, S2 projet, S3-4 autonomie, M2 eval', 'rh', 'best_practice', 0.80, 'omega', 'system'),
('OMEGA_16: Le marketing influencer ROI tracking: cout partenariat / (impressions × CVR × AOV) = cout par vente. Si < CAC habituel = partenariat rentable.', 'Influencer ROI: cout / (impressions × CVR × AOV) = cout/vente. < CAC = rentable', 'marketing', 'best_practice', 0.80, 'omega', 'system'),
('OMEGA_17: Le cross-agent prospect scoring unified: email engagement (25%) + social interaction (20%) + site behavior (25%) + CRM qualification (20%) + fit score (10%).', 'Scoring unifie: email 25% + social 20% + site 25% + CRM 20% + fit 10%', NULL, 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_18: Le customer data enrichment pipeline: email capture → firmographic enrichment (type, taille, localisation) → social enrichment (IG, TikTok, followers) → scoring auto.', 'Enrichment pipeline: capture → firmographic → social → scoring auto', NULL, 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_19: Le KeiroAI agent learning protocol: chaque execution est logguee. Chaque semaine, les patterns sont analyses. Les insights sont stockes dans le RAG. Boucle d amelioration.', 'Agent learning: log → analyse patterns → RAG → amelioration. Boucle hebdo', NULL, 'best_practice', 0.88, 'omega', 'system'),
('OMEGA_20: Le KeiroAI scalability design: architecture multi-tenant avec isolation des donnees par client. Chaque client a ses propres prospects, contenus, et configurations.', 'KeiroAI scalability: multi-tenant, isolation donnees par client', 'ceo', 'best_practice', 0.88, 'omega', 'system'),
('OMEGA_21: Le email personalization engine: chaque email est personnalise avec: prenom, type de commerce, derniere interaction, score prospect, contenu adapte au segment.', 'Email perso engine: prenom + type + derniere interaction + score + contenu segment', 'email', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_22: Le commercial objection handling LAER: Listen (ecouter) → Acknowledge (reconnaitre) → Explore (approfondir) → Respond (repondre). Dans cet ordre.', 'Objection LAER: Listen → Acknowledge → Explore → Respond', 'commercial', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_23: Le content viral coefficient: si chaque post est partage par 10% des viewers, et 5% des partages generent un nouveau follower, le coefficient viral = 0.005 × followers.', 'Viral coefficient: share rate × follow-from-share × followers', 'content', 'insight', 0.78, 'omega', 'system'),
('OMEGA_24: Le SEO page experience update 2026: Google mesure maintenant le INP (Interaction to Next Paint) au lieu du FID. INP < 200ms = bon.', 'SEO 2026: INP remplace FID. INP < 200ms = bon', 'seo', 'insight', 0.85, 'omega', 'system'),
('OMEGA_25: Le ad audience refresh strategy: tous les 30 jours, creer de nouvelles audiences basees sur les derniers purchasers/signups. Les audiences vieillissent et perdent en efficacite.', 'Audience refresh 30j: nouvelles basees sur derniers purchasers/signups', 'ads', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_26: Le DM Instagram value-first template: Salut [prenom]! J ai vu ton post sur [sujet] — vraiment top. J ai un [template/guide/astuce] qui pourrait t aider avec [besoin specifique]. Ca t interesse?', 'DM template value-first: compliment post + offre valeur + question ouverte', 'dm_instagram', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_27: Le WhatsApp flow commerce complet: catalogue → selection → panier → checkout → paiement → confirmation → suivi livraison → satisfaction. Tout dans WhatsApp.', 'WhatsApp commerce complet: catalogue→panier→checkout→paiement→confirm→suivi→satisfaction', 'whatsapp', 'best_practice', 0.80, 'omega', 'system'),
('OMEGA_28: Le chatbot contextual memory: retenir les informations des conversations precedentes (nom, preferences, historique). Un chatbot qui se souvient = +30% satisfaction.', 'Chatbot memoire contextuelle: retenir nom+prefs+historique = +30% satisfaction', 'chatbot', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_29: Le GMaps business description optimization: 750 caracteres max. Inclure: activite principale + specialites + localisation + avantage competitif + CTA.', 'GMaps description 750 chars: activite + specialites + localisation + avantage + CTA', 'gmaps', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_30: Le TikTok engagement hack: poser une question controversee dans le texte overlay. Les debats en commentaires font exploser l algorithme (+5x portee).', 'TikTok question controversee = debats commentaires = 5x portee', 'tiktok_comments', 'insight', 0.80, 'omega', 'system'),
('OMEGA_31: Le CEO risk assessment matrix: pour chaque risque, evaluer Probabilite (1-5) × Impact (1-5). Score > 15 = mitiger immediatement. Score 8-15 = surveiller.', 'CEO risk: Probabilite × Impact. > 15 = mitiger. 8-15 = surveiller', 'ceo', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_32: Le retention feature adoption tracking: lister les 10 features cles. Pour chaque client, tracker combien il utilise. < 3 features = risque churn.', 'Feature adoption: 10 features cles. Client < 3 = risque churn', 'retention', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_33: Le onboarding personalization by plan: Createur → focus contenu IG. Pro → focus multi-canal. Fondateurs → focus strategie + CRM. Business → focus equipe + rapports.', 'Onboarding par plan: Createur IG, Pro multi-canal, Fondateurs strategie, Business equipe', 'onboarding', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_34: Le comptable SaaS metrics glossary: MRR, ARR, ARPU, LTV, CAC, LTV/CAC, NRR, GRR, payback, rule of 40, burn multiple, magic number. Les 12 essentiels.', 'SaaS glossary: MRR, ARR, ARPU, LTV, CAC, ratio, NRR, GRR, payback, R40, burn, magic', 'comptable', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_35: Le RH stay interview questions: pourquoi restez-vous? qu est-ce qui pourrait vous faire partir? que changeriez-vous? quelles sont vos aspirations? comment je peux vous aider?', 'Stay interview: pourquoi rester? quoi ferait partir? changer? aspirations? aider?', 'rh', 'best_practice', 0.80, 'omega', 'system'),
('OMEGA_36: Le marketing owned media strategy: blog + newsletter + app + communaute. Les seuls canaux qu on controle. Les reseaux sociaux peuvent changer les regles n importe quand.', 'Owned media: blog+newsletter+app+communaute = seuls canaux controles', 'marketing', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_37: Le inter-agent learning transfer: quand l agent email decouvre qu un sujet a un OR de 40%, cette info est partagee avec le contenu (creer du contenu sur ce sujet) et les ads (tester ce message).', 'Learning transfer: email OR 40% sujet → contenu cree + ads teste ce message', NULL, 'best_practice', 0.88, 'omega', 'system'),
('OMEGA_38: Le predictive lead scoring model: combiner comportement (site visits, email engagement) + firmographic (taille, secteur) + intent (pricing page, demo request) = score predictif.', 'Predictive scoring: comportement + firmographic + intent = score predictif', NULL, 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_39: Le KeiroAI quality gate system: chaque output agent passe par un check: pertinence (1-5) × brand alignment (1-5) × qualite (1-5). Score < 9/15 = regenerer.', 'Quality gate: pertinence × brand × qualite sur 5. < 9/15 = regenerer', NULL, 'best_practice', 0.88, 'omega', 'system'),
('OMEGA_40: Le KeiroAI vision 2027: agents autonomes niveau 4 qui executent, apprennent et s ameliorent sans intervention. Le client dort, ses agents travaillent.', 'KeiroAI 2027: agents autonomes L4. Client dort, agents travaillent', 'ceo', 'insight', 0.90, 'omega', 'system'),
('OMEGA_41: Le email split testing advanced: tester subject (semaine 1), from name (semaine 2), send time (semaine 3), CTA (semaine 4), contenu (semaine 5). 1 variable/semaine.', 'Email testing: subject S1, from S2, time S3, CTA S4, contenu S5. 1 var/sem', 'email', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_42: Le commercial discovery call checklist: pain identifie? budget discute? decision maker confirme? timeline definie? competition evaluee? Si 4/5 oui = deal qualifie.', 'Discovery checklist: pain+budget+DM+timeline+competition. 4/5 oui = qualifie', 'commercial', 'best_practice', 0.85, 'omega', 'system'),
('OMEGA_43: Le content engagement rate calculation: (interactions totales / reach) × 100. Benchmark: IG 1-3%, LI 2-5%, TT 3-8%, X 0.5-1.5%.', 'Engagement rate: interactions/reach × 100. IG 1-3%, LI 2-5%, TT 3-8%, X 0.5-1.5%', 'content', 'insight', 0.85, 'omega', 'system'),
('OMEGA_44: Le SEO schema markup priority: Article, FAQ, HowTo, LocalBusiness, Product, Review, Organization. Implementer dans cet ordre de priorite.', 'Schema priority: Article→FAQ→HowTo→Local→Product→Review→Organization', 'seo', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_45: Le ad creative winner scaling: une fois un winner identifie (CTR > 2x moyenne), augmenter le budget de 20%/jour pendant 5 jours. Si performance tient = continuer.', 'Winner scaling: CTR >2x → +20%/jour × 5j. Performance tient = continuer', 'ads', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_46: Le DM follow-up science: si pas de reponse J+3 → envoyer 1 message de valeur (pas de relance directe). Si toujours rien J+7 → derniere tentative avec CTA clair.', 'DM follow-up: J+3 valeur (pas relance), J+7 derniere tentative CTA', 'dm_instagram', 'best_practice', 0.82, 'omega', 'system'),
('OMEGA_47: Le WhatsApp opt-in compliance: collecter le consentement explicite + documenter la date/source + proposer l opt-out dans chaque message + respecter le RGPD.', 'WhatsApp compliance: consentement + documenter + opt-out + RGPD', 'whatsapp', 'best_practice', 0.90, 'omega', 'system'),
('OMEGA_48: Le chatbot multilingual detection: detecter la langue du premier message et repondre dans cette langue. Supporter FR, EN, ES, DE minimum pour l Europe.', 'Chatbot multilingual: detecter langue message 1 → repondre dans cette langue', 'chatbot', 'best_practice', 0.80, 'omega', 'system'),
('OMEGA_49: Le GMaps local pack algorithm: les 3 facteurs dans l ordre: 1) pertinence (categories + description), 2) distance (proximite), 3) importance (avis + citations + backlinks).', 'GMaps pack local: 1) pertinence 2) distance 3) importance (avis+citations+backlinks)', 'gmaps', 'insight', 0.88, 'omega', 'system'),
('OMEGA_50: Le TikTok growth compound effect: chaque video virale amene des followers → plus de baseline views sur les prochaines videos → plus de chances de viralite. Effet compose.', 'TikTok compound: virale → followers → baseline views → plus viralite. Compose', 'tiktok_comments', 'insight', 0.82, 'omega', 'system')
